const updateWorkspaces=({content:e,originalContent:s={}})=>{const o=e.workspaces;if(!o)return s;if(!o.length||o.some(e=>!("string"==typeof e)))throw Object.assign(new TypeError("workspaces should be an array of strings."),{code:"EWORKSPACESINVALID"});return{...s,workspaces:[...o]}};module.exports=updateWorkspaces;